  1	import * as React from 'react';
  2	import { Button, ButtonVariant, Tooltip, TooltipPosition } from '@patternfly/react-core';
  3	import { ListIcon, ThIcon, ThLargeIcon } from '@patternfly/react-icons';
  4	import { SortAlphaDownIcon, SortAlphaUpIcon } from '@patternfly/react-icons';
  5	import { connect } from 'react-redux';
  6	import { UserSettingsActions } from '../../actions/UserSettingsActions';
  7	import { HistoryManager, URLParam } from '../../app/History';
  8	import { StatefulFilters, StatefulFiltersRef } from '../../components/Filters/StatefulFilters';
  9	import * as FilterHelper from '../../components/FilterList/FilterHelper';
 10	import { ToolbarDropdown } from '../../components/Dropdown/ToolbarDropdown';
 11	import { KialiAppState } from '../../store/Store';
 12	import { durationSelector, languageSelector, refreshIntervalSelector } from '../../store/Selectors';
 13	import { IntervalInMilliseconds, DurationInSeconds } from '../../types/Common';
 14	import { SortField } from '../../types/SortFilters';
 15	import { NamespaceInfo } from '../../types/NamespaceInfo';
 16	import * as Sorts from './Sorts';
 17	import * as Filters from './Filters';
 18	import { kialiStyle } from 'styles/StyleUtils';
 19	import { TimeDurationComponent } from '../../components/Time/TimeDurationComponent';
 20	import { KialiDispatch } from '../../types/Redux';
 21	import { PFColors } from 'components/Pf/PfColors';
 22	import { t, tMap } from 'utils/I18nUtils';
 23	
 24	// TODO: Are any of these redux state or dispatch props used?
 25	type ReduxStateProps = {
 26	  duration: DurationInSeconds;
 27	  language: string;
 28	  refreshInterval: IntervalInMilliseconds;
 29	};
 30	
 31	type ReduxDispatchProps = {
 32	  setRefreshInterval: (refresh: IntervalInMilliseconds) => void;
 33	};
 34	
 35	type Props = ReduxStateProps &
 36	  ReduxDispatchProps & {
 37	    displayMode: OverviewDisplayMode;
 38	    onError: (msg: string) => void;
 39	    onChange: () => void;
 40	    onRefresh: () => void;
 41	    setDisplayMode: (mode: OverviewDisplayMode) => void;
 42	    sort: (sortField: SortField<NamespaceInfo>, isAscending: boolean) => void;
 43	    statefulFilterRef: StatefulFiltersRef;
 44	  };
 45	
 46	export enum OverviewDisplayMode {
 47	  COMPACT,
 48	  EXPAND,
 49	  LIST
 50	}
 51	
 52	const overviewTypes = {
 53	  app: t('Apps'),
 54	  workload: t('Workloads'),
 55	  service: t('Services')
 56	};
 57	
 58	const directionTypes = {
 59	  inbound: t('Inbound'),
 60	  outbound: t('Outbound')
 61	};
 62	
 63	const sortTypes = (() => {
 64	  return Object.fromEntries(Sorts.sortFields.map(sortType => [sortType.id, t(sortType.title)]));
 65	})();
 66	
 67	const containerStyle = kialiStyle({
 68	  padding: '0 1.25rem 0 1.25rem',
 69	  backgroundColor: PFColors.BackgroundColor100,
 70	  borderBottom: `1px solid ${PFColors.BorderColor100}`
 71	});
 72	
 73	const containerFlex = kialiStyle({
 74	  display: 'flex',
 75	  flexWrap: 'wrap'
 76	});
 77	
 78	const filterToolbarStyle = kialiStyle({
 79	  paddingTop: '0.625rem'
 80	});
 81	
 82	const rightToolbarStyle = kialiStyle({
 83	  marginLeft: 'auto',
 84	  height: '118px',
 85	  padding: '0.625rem 0 0 0'
 86	});
 87	
 88	const timeToolbarStyle = kialiStyle({
 89	  textAlign: 'right'
 90	});
 91	
 92	const actionsToolbarStyle = kialiStyle({
 93	  paddingTop: '1rem',
 94	  display: 'flex',
 95	  justifyContent: 'end',
 96	  alignItems: 'center'
 97	});
 98	
 99	const typeSelectStyle = kialiStyle({
100	  marginRight: '0.5rem'
101	});
102	
103	export type OverviewType = keyof typeof overviewTypes;
104	
105	export type DirectionType = keyof typeof directionTypes;
106	
107	type State = {
108	  directionType: DirectionType;
109	  isSortAscending: boolean;
110	  overviewType: OverviewType;
111	  sortField: SortField<NamespaceInfo>;
112	};
113	
114	class OverviewToolbarComponent extends React.Component<Props, State> {
115	  static currentOverviewType = (): OverviewType => {
116	    const otype = HistoryManager.getParam(URLParam.OVERVIEW_TYPE);
117	    return (otype as OverviewType) ?? 'app';
118	  };
119	
120	  static currentDirectionType = (): DirectionType => {
121	    const drtype = HistoryManager.getParam(URLParam.DIRECTION_TYPE);
122	    return (drtype as DirectionType) ?? 'inbound';
123	  };
124	
125	  constructor(props: Props) {
126	    super(props);
127	
128	    this.state = {
129	      isSortAscending: FilterHelper.isCurrentSortAscending(),
130	      overviewType: OverviewToolbar.currentOverviewType(),
131	      directionType: OverviewToolbar.currentDirectionType(),
132	      sortField: FilterHelper.currentSortField(Sorts.sortFields)
133	    };
134	  }
135	
136	  componentDidUpdate(): void {
137	    const urlSortField = FilterHelper.currentSortField(Sorts.sortFields);
138	    const urlIsSortAscending = FilterHelper.isCurrentSortAscending();
139	
140	    if (!this.paramsAreSynced(urlSortField, urlIsSortAscending)) {
141	      this.setState({
142	        sortField: urlSortField,
143	        isSortAscending: urlIsSortAscending
144	      });
145	    }
146	  }
147	
148	  paramsAreSynced = (urlSortField: SortField<NamespaceInfo>, urlIsSortAscending: boolean): boolean => {
149	    return urlIsSortAscending === this.state.isSortAscending && urlSortField.title === this.state.sortField.title;
150	  };
151	
152	  updateSortField = (sortField: SortField<NamespaceInfo>): void => {
153	    this.props.sort(sortField, this.state.isSortAscending);
154	    HistoryManager.setParam(URLParam.SORT, sortField.param);
155	    this.setState({ sortField: sortField });
156	  };
157	
158	  updateSortDirection = (): void => {
159	    const newDir = !this.state.isSortAscending;
160	    this.props.sort(this.state.sortField, newDir);
161	    HistoryManager.setParam(URLParam.DIRECTION, newDir ? 'asc' : 'desc');
162	    this.setState({ isSortAscending: newDir });
163	  };
164	
165	  updateOverviewType = (otype: String): void => {
166	    const isOverviewType = (val: String): val is OverviewType =>
167	      val === 'app' || val === 'workload' || val === 'service';
168	
169	    if (isOverviewType(otype)) {
170	      HistoryManager.setParam(URLParam.OVERVIEW_TYPE, otype);
171	      this.setState({ overviewType: otype });
172	      this.props.onChange();
173	    } else {
174	      throw new Error(t('Overview type is not valid.'));
175	    }
176	  };
177	
178	  updateDirectionType = (dtype: String): void => {
179	    const isDirectionType = (val: String): val is DirectionType => val === 'inbound' || val === 'outbound';
180	
181	    if (isDirectionType(dtype)) {
182	      HistoryManager.setParam(URLParam.DIRECTION_TYPE, dtype);
183	      this.setState({ directionType: dtype });
184	      this.props.onChange();
185	    } else {
186	      throw new Error(t('Direction type is not valid.'));
187	    }
188	  };
189	
190	  changeSortField = (value: string): void => {
191	    const sortField: SortField<NamespaceInfo> = Sorts.sortFields.filter(sort => sort.id === value)[0];
192	    this.props.sort(sortField, this.state.isSortAscending);
193	    HistoryManager.setParam(URLParam.SORT, sortField.param);
194	    this.setState({ sortField: sortField });
195	  };
196	
197	  render(): React.ReactNode {
198	    const filterToolbar = (
199	      <StatefulFilters
200	        initialFilters={Filters.availableFilters}
201	        onFilterChange={this.props.onChange}
202	        ref={this.props.statefulFilterRef}
203	      >
204	        {this.props.displayMode !== OverviewDisplayMode.LIST && (
205	          <>
206	            <ToolbarDropdown
207	              id="sort_selector"
208	              handleSelect={this.changeSortField}
209	              value={this.state.sortField.id}
210	              label={t(sortTypes[this.state.sortField.id])}
211	              options={tMap(sortTypes)}
212	              data-sort-field={this.state.sortField.id}
213	            />
214	
215	            <Button
216	              variant={ButtonVariant.plain}
217	              onClick={this.updateSortDirection}
218	              style={{ paddingLeft: '0.5rem', paddingRight: '0.5rem' }}
219	              data-sort-asc={this.state.isSortAscending}
220	            >
221	              {this.state.isSortAscending ? <SortAlphaDownIcon /> : <SortAlphaUpIcon />}
222	            </Button>
223	          </>
224	        )}
225	      </StatefulFilters>
226	    );
227	
228	    const timeToolbar = (
229	      <div className={timeToolbarStyle}>
230	        <TimeDurationComponent key="overview-time-range" id="overview-time-range" disabled={false} />
231	      </div>
232	    );
233	
234	    const actionsToolbar = (
235	      <div className={actionsToolbarStyle}>
236	        <ToolbarDropdown
237	          id="overview-type"
238	          disabled={false}
239	          className={typeSelectStyle}
240	          handleSelect={this.updateOverviewType}
241	          nameDropdown={t('Health for')}
242	          value={this.state.overviewType}
243	          label={t(overviewTypes[this.state.overviewType])}
244	          options={tMap(overviewTypes)}
245	        />
246	
247	        {this.props.displayMode !== OverviewDisplayMode.COMPACT && (
248	          <ToolbarDropdown
249	            id="direction-type"
250	            disabled={false}
251	            handleSelect={this.updateDirectionType}
252	            nameDropdown={t('Traffic')}
253	            value={this.state.directionType}
254	            label={t(directionTypes[this.state.directionType])}
255	            options={tMap(directionTypes)}
256	          />
257	        )}
258	
259	        <Tooltip content={<>{t('Expand view')}</>} position={TooltipPosition.top}>
260	          <Button
261	            onClick={() => this.props.setDisplayMode(OverviewDisplayMode.EXPAND)}
262	            variant={ButtonVariant.plain}
263	            isActive={this.props.displayMode === OverviewDisplayMode.EXPAND}
264	            style={{ padding: '0 0.25rem 0 1rem' }}
265	            data-test={`overview-type-${OverviewDisplayMode[OverviewDisplayMode.EXPAND]}`}
266	          >
267	            <ThLargeIcon />
268	          </Button>
269	        </Tooltip>
270	
271	        <Tooltip content={<>{t('Compact view')}</>} position={TooltipPosition.top}>
272	          <Button
273	            onClick={() => this.props.setDisplayMode(OverviewDisplayMode.COMPACT)}
274	            variant={ButtonVariant.plain}
275	            isActive={this.props.displayMode === OverviewDisplayMode.COMPACT}
276	            style={{ padding: '0 0.25rem 0 0.25rem' }}
277	            data-test={`overview-type-${OverviewDisplayMode[OverviewDisplayMode.COMPACT]}`}
278	          >
279	            <ThIcon />
280	          </Button>
281	        </Tooltip>
282	
283	        <Tooltip content={<>{t('List view')}</>} position={TooltipPosition.top}>
284	          <Button
285	            onClick={() => this.props.setDisplayMode(OverviewDisplayMode.LIST)}
286	            variant={ButtonVariant.plain}
287	            isActive={this.props.displayMode === OverviewDisplayMode.LIST}
288	            style={{ padding: '0 0.25rem 0 0.25rem' }}
289	            data-test={`overview-type-${OverviewDisplayMode[OverviewDisplayMode.LIST]}`}
290	          >
291	            <ListIcon />
292	          </Button>
293	        </Tooltip>
294	      </div>
295	    );
296	
297	    return (
298	      <div className={containerStyle}>
299	        <div className={containerFlex}>
300	          <div className={filterToolbarStyle}>{filterToolbar}</div>
301	          <div className={rightToolbarStyle}>
302	            {timeToolbar}
303	            {actionsToolbar}
304	          </div>
305	        </div>
306	      </div>
307	    );
308	  }
309	}
310	
311	const mapStateToProps = (state: KialiAppState): ReduxStateProps => ({
312	  duration: durationSelector(state),
313	  refreshInterval: refreshIntervalSelector(state),
314	  language: languageSelector(state)
315	});
316	
317	const mapDispatchToProps = (dispatch: KialiDispatch): ReduxDispatchProps => {
318	  return {
319	    setRefreshInterval: (refreshInterval: IntervalInMilliseconds) => {
320	      dispatch(UserSettingsActions.setRefreshInterval(refreshInterval));
321	    }
322	  };
323	};
324	
325	export const OverviewToolbar = connect(mapStateToProps, mapDispatchToProps)(OverviewToolbarComponent);

